package com.example.enterpriseapp.transaction;

import com.example.enterpriseapp.user.AppUser;
import com.example.enterpriseapp.user.AppUserService;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import java.math.BigDecimal;
import java.util.List;

@Service
@Transactional
public class AppTransactionService {
    private final AppTransactionRepository appTransactionRepository;
    private final AppUserService appUserService;

    public AppTransactionService(AppTransactionRepository appTransactionRepository, AppUserService appUserService) {
        this.appTransactionRepository = appTransactionRepository;
        this.appUserService = appUserService;
    }

    public AppTransaction createTransaction(Long userId, BigDecimal amount, String type) {
        AppUser user = appUserService.getUserById(userId);
        AppTransaction transaction = new AppTransaction(user, amount, type, "PENDING");
        return appTransactionRepository.save(transaction);
    }

    @Transactional(readOnly = true)
    public List<AppTransaction> getTransactionsByUser(Long userId) {
        return appTransactionRepository.findByUserId(userId);
    }

    @Transactional(readOnly = true)
    public List<AppTransaction> getTransactionsByStatus(String status) {
        return appTransactionRepository.findByStatus(status);
    }

    public AppTransaction updateTransactionStatus(Long transactionId, String status) {
        AppTransaction transaction = appTransactionRepository.findById(transactionId)
                .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
        transaction.setStatus(status);
        return appTransactionRepository.save(transaction);
    }

    public void deleteTransaction(Long transactionId) {
        appTransactionRepository.deleteById(transactionId);
    }
}

package com.example.enterpriseapp.web;

import com.example.enterpriseapp.transaction.AppTransaction;
import com.example.enterpriseapp.transaction.AppTransactionService;
import com.example.enterpriseapp.user.AppUser;
import com.example.enterpriseapp.user.AppUserService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import java.math.BigDecimal;
import java.util.List;

@RestController
@RequestMapping("/api")
public class EnterpriseController {
    private final AppUserService appUserService;
    private final AppTransactionService appTransactionService;

    public EnterpriseController(AppUserService appUserService, AppTransactionService appTransactionService) {
        this.appUserService = appUserService;
        this.appTransactionService = appTransactionService;
    }

    @PostMapping("/users")
    public ResponseEntity<AppUser> createUser(@RequestBody AppUser user) {
        return ResponseEntity.ok(appUserService.createUser(user));
    }

    @GetMapping("/users/{id}")
    public ResponseEntity<AppUser> getUser(@PathVariable Long id) {
        return ResponseEntity.ok(appUserService.getUserById(id));
    }

    @GetMapping("/users")
    public ResponseEntity<List<AppUser>> getAllUsers() {
        return ResponseEntity.ok(appUserService.getAllUsers());
    }

    @PutMapping("/users/{id}")
    public ResponseEntity<AppUser> updateUser(@PathVariable Long id, @RequestBody AppUser user) {
        return ResponseEntity.ok(appUserService.updateUser(id, user));
    }

    @DeleteMapping("/users/{id}")
    public ResponseEntity<Void> deleteUser(@PathVariable Long id) {
        appUserService.deleteUser(id);
        return ResponseEntity.noContent().build();
    }

    @PostMapping("/transactions")
    public ResponseEntity<AppTransaction> createTransaction(@RequestParam Long userId,
                                                             @RequestParam BigDecimal amount,
                                                             @RequestParam String type) {
        return ResponseEntity.ok(appTransactionService.createTransaction(userId, amount, type));
    }

    @GetMapping("/transactions/user/{userId}")
    public ResponseEntity<List<AppTransaction>> getTransactionsByUser(@PathVariable Long userId) {
        return ResponseEntity.ok(appTransactionService.getTransactionsByUser(userId));
    }

    @GetMapping("/transactions/status/{status}")
    public ResponseEntity<List<AppTransaction>> getTransactionsByStatus(@PathVariable String status) {
        return ResponseEntity.ok(appTransactionService.getTransactionsByStatus(status));
    }

    @PutMapping("/transactions/{id}/status")
    public ResponseEntity<AppTransaction> updateTransactionStatus(@PathVariable Long id,
                                                                   @RequestParam String status) {
        return ResponseEntity.ok(appTransactionService.updateTransactionStatus(id, status));
    }

    @DeleteMapping("/transactions/{id}")
    public ResponseEntity<Void> deleteTransaction(@PathVariable Long id) {
        appTransactionService.deleteTransaction(id);
        return ResponseEntity.noContent().build();
    }
}

